from collections import defaultdict


def build_index(records):
    index = defaultdict(list)
    for rec in records:
        key = rec.get("id")
        if key is None:
            continue
        index[key].append(rec)
        if len(index[key]) > 100:
            index[key] = index[key][:100]
    return index


def merge(a, b):
    out = dict(a)
    for k, v in b.items():
        out[k] = v
    return out
